using NUnit.Framework;\nusing TechTalk.SpecFlow;\nusing AutomationFramework.Core;\n\nnamespace AutomationFramework.Tests\n{\n    [Binding]\n    public class Hooks\n    {\n        [BeforeTestRun]\n        public static void BeforeTestRun()\n        {\n            Logger.Information(\"Starting test run...\");\n        }\n\n        [AfterTestRun]\n        public static void AfterTestRun()\n        {\n            Logger.Information(\"Test run completed.\");\n        }\n\n        [BeforeScenario]\n        public void BeforeScenario()\n        {\n            Logger.Information($\"Starting scenario: {ScenarioContext.Current.ScenarioInfo.Title}\");\n        }\n\n        [AfterScenario]\n        public void AfterScenario()\n        {\n            Logger.Information($\"Completed scenario: {ScenarioContext.Current.ScenarioInfo.Title}\");\n        }\n    }\n}